-- VERIFICACIÓN: Contar leads por mes de cierre en la base de datos
SELECT 
    to_char(internal_won_date, 'YYYY-MM') as mes,
    COUNT(*) as total_leads,
    SUM(COALESCE(closing_amount, value, 0)) as monto_total
FROM public.leads
WHERE status IN ('Cerrado', 'Cliente')
  AND internal_won_date IS NOT NULL
GROUP BY to_char(internal_won_date, 'YYYY-MM')
ORDER BY mes DESC;
